ValidationRule.errorConditionFormula:
OR(
    AND(
        OR(NOT(ISBLANK(APHA_TestDay1Avian__c)), NOT(ISBLANK(APHA_TestDay1Bovine__c))),
        NOT(ISBLANK(APHA_TestDay1DIVA__c))
    ),

    AND(
        ISBLANK(APHA_TestDay1DIVA__c),
        OR(
            AND(NOT(ISBLANK(APHA_TestDay1Avian__c)), ISBLANK(APHA_TestDay1Bovine__c)),
            AND(ISBLANK(APHA_TestDay1Avian__c), NOT(ISBLANK(APHA_TestDay1Bovine__c)))
        )
    )
)
